    // term * cospiz
    final mulX = termX * cospizX - termY * cospizY;
    final mulY = termX * cospizY + termY * cospizX;

    final nx = 0.25 * (2.0 + 7.0 * zx - mulX);
    final ny = 0.25 * (7.0 * zy - mulY);
